// Parse and validate Hospitable webhook payload
const body = $input.first().json.body || $input.first().json;
const headers = $input.first().json.headers || {};
const eventType = body.event || body.type || '';

// Route: only handle listing events
const listingEvents = ['listing.created', 'listing.updated', 'listing.deleted', 'calendar.updated'];
if (!listingEvents.includes(eventType)) {
  return [{ json: { skip: true, reason: `Not a listing event: ${eventType}` } }];
}

const listing = body.data || body.listing || body.payload || {};
const customerId = body.customer_id || listing.customer_id || '';

return [{
  json: {
    skip: false,
    eventType,
    customerId,
    listingId: listing.id || listing.listing_id || '',
    listing,
    isDelete: eventType === 'listing.deleted',
    isCalendar: eventType === 'calendar.updated',
    webhookId: body.id || body.webhook_id || crypto.randomUUID()
  }
}];

// Check idempotency via nfs_webhook_events
const webhookId = $input.first().json.webhookId;
const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;

const existing = await this.helpers.httpRequest({
  method: 'GET',
  url: `${supabaseUrl}/rest/v1/nfs_webhook_events?external_event_id=eq.${webhookId}&select=id`,
  headers: {
    'apikey': serviceKey,
    'Authorization': `Bearer ${serviceKey}`,
    'Accept': 'application/json'
  }
});

if (existing && existing.length > 0) {
  return [{ json: { ...($input.first().json), duplicate: true } }];
}

// Record the event
await this.helpers.httpRequest({
  method: 'POST',
  url: `${supabaseUrl}/rest/v1/nfs_webhook_events`,
  headers: {
    'apikey': serviceKey,
    'Authorization': `Bearer ${serviceKey}`,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: {
    source: 'hospitable',
    external_event_id: webhookId,
    event_type: $input.first().json.eventType,
    data: $input.first().json.listing,
    processed: false
  }
});

return [{ json: { ...($input.first().json), duplicate: false } }];

// Upsert listing to nfs_properties
const data = $input.first().json;
if (data.duplicate) {
  return [{ json: { action: 'skipped_duplicate', listingId: data.listingId } }];
}

const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;
const listing = data.listing;

if (data.isDelete) {
  // Archive the property
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${supabaseUrl}/rest/v1/nfs_properties?hospitable_property_id=eq.${data.listingId}`,
    headers: {
      'apikey': serviceKey,
      'Authorization': `Bearer ${serviceKey}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: {
      listing_status: 'archived',
      hospitable_sync_status: 'completed',
      hospitable_last_sync_at: new Date().toISOString()
    }
  });
  return [{ json: { action: 'archived', listingId: data.listingId } }];
}

if (data.isCalendar) {
  // Update blocked dates only
  const blockedDates = listing.blocked_dates || listing.blocked_date_ranges || [];
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${supabaseUrl}/rest/v1/nfs_properties?hospitable_property_id=eq.${data.listingId}`,
    headers: {
      'apikey': serviceKey,
      'Authorization': `Bearer ${serviceKey}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: {
      blocked_date_ranges: blockedDates,
      hospitable_last_sync_at: new Date().toISOString()
    }
  });
  return [{ json: { action: 'calendar_updated', listingId: data.listingId } }];
}

// Full listing upsert
const prop = {
  public_title: listing.public_name || listing.name || listing.title || '',
  description: listing.description || '',
  address: listing.address?.street || '',
  city: listing.address?.city || '',
  country: listing.address?.country_code || 'GB',
  lat: listing.address?.latitude || null,
  lng: listing.address?.longitude || null,
  max_guests: listing.capacity?.max || 4,
  images: listing.picture ? [{ url: listing.picture.replace(/\\?aki_policy=[^&]+/, ''), caption: '', order: 0, is_cover: true }] : [],
  amenities: listing.amenities || [],
  base_rate_amount: listing.base_price || 100,
  hospitable_last_sync_at: new Date().toISOString(),
  hospitable_sync_status: 'completed'
};

await this.helpers.httpRequest({
  method: 'PATCH',
  url: `${supabaseUrl}/rest/v1/nfs_properties?hospitable_property_id=eq.${data.listingId}`,
  headers: {
    'apikey': serviceKey,
    'Authorization': `Bearer ${serviceKey}`,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: prop
});

// Mark webhook event as processed
await this.helpers.httpRequest({
  method: 'PATCH',
  url: `${supabaseUrl}/rest/v1/nfs_webhook_events?external_event_id=eq.${data.webhookId}`,
  headers: {
    'apikey': serviceKey,
    'Authorization': `Bearer ${serviceKey}`,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: { processed: true, success: true, processed_at: new Date().toISOString() }
});

return [{ json: { action: 'upserted', listingId: data.listingId } }];
